INSERT INTO `formation` (`id_formation`, `titre`, `description`, `domaine`, `niveau`, `date_formation`, `image_base64`, `duree`, `id_tuteur`, `is_online`, `lien_api_room`, `statut`, `prerequis_id`, `date_fin`) VALUES
(25, ' Initiation au Web (HTML & CSS)', '<p>Découvrez comment structurer et styliser une page web de A à Z.</p><hr style=\"margin: 2rem 0; border: none; border-top: 1px dashed var(--border-color);\"><h4 style=\"color:var(--accent-primary);\">Syllabus Proposé</h4><p style=\"margin-bottom:1rem;\">Plongez dans l\'univers de la création numérique avec cette formation complète conçue pour les débutants. Maîtrisez les fondations du Web en apprenant à structurer vos idées avec HTML5 et à leur donner vie visuellement avec CSS3, pour devenir autonome dans la réalisation de vos premiers sites internet.</p><ul style=\"list-style-type:none; padding:0; margin:0;\">\r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Introduction et Architecture du Web <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 1h00</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Comprendre le fonctionnement d\'un navigateur, le modèle client-serveur et configurer l\'environnement de développement (VS Code).</div>\r\n                </li>\r\n            </ul><hr style=\"margin: 2rem 0; border: none; border-top: 1px dashed var(--border-color);\"><h4 style=\"color:var(--accent-primary);\">Syllabus Proposé</h4><p style=\"margin-bottom:1rem;\">Devenez autonome dans la création de sites web en maîtrisant les deux langages piliers du web : le HTML pour la structure et le CSS pour le design. Une formation pratique conçue pour transformer les débutants en créateurs de contenus web modernes.</p><ul style=\"list-style-type:none; padding:0; margin:0;\">\r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Introduction au Web et fondamentaux du HTML <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 1h30</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Comprendre le fonctionnement du web (client/serveur) et créer sa première structure de page avec les balises de base.</div>\r\n                </li>\r\n            </ul><hr style=\"margin: 2rem 0; border: none; border-top: 1px dashed var(--border-color);\"><h4 style=\"color:var(--accent-primary);\">Syllabus Proposé</h4><p style=\"margin-bottom:1rem;\">Devenez l\'architecte du web en maîtrisant les fondations essentielles : structurez vos idées avec HTML5 et donnez-leur vie avec le design élégant de CSS3.</p><ul style=\"list-style-type:none; padding:0; margin:0;\">\r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Introduction au Web et à l\'HTML5 <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 1h30</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Comprendre le fonctionnement d\'Internet, le rôle du navigateur et la structure fondamentale d\'un document HTML.</div>\r\n                </li>\r\n            \r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Introduction au CSS3 : Styliser le Web <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 2h30</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Découverte des sélecteurs, des propriétés de couleur, de typographie et l\'application de styles externes.</div>\r\n                </li>\r\n            </ul><hr style=\"margin: 2rem 0; border: none; border-top: 1px dashed var(--border-color);\"><h4 style=\"color:var(--accent-primary);\">Syllabus Proposé</h4><p style=\"margin-bottom:1rem;\">Devenez autonome dans la création de sites web en maîtrisant les deux piliers du front-end : le HTML5 pour la structure et le CSS3 pour le design.</p><ul style=\"list-style-type:none; padding:0; margin:0;\">\r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Introduction au fonctionnement du Web <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 1h00</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Comprendre les bases du protocole HTTP, le rôle du serveur, du navigateur et la structure d\'une URL.</div>\r\n                </li>\r\n            \r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Structure fondamentale avec HTML5 <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 2h00</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Apprentissage de la syntaxe HTML, des balises sémantiques (header, nav, main, footer) et de l\'arborescence d\'un document.</div>\r\n                </li>\r\n            \r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Textes, Liens et Listes <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 1h30</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Mise en forme du contenu textuel, création de liens hypertextes et organisation des données en listes ordonnées ou non.</div>\r\n                </li>\r\n            \r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Multimédia et Formulaires <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 2h00</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Intégration d\'images, de vidéos et conception de formulaires interactifs pour la saisie de données utilisateur.</div>\r\n                </li>\r\n            \r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Introduction au CSS3 <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 2h00</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Syntaxe CSS, méthodes d\'intégration, sélecteurs de base et gestion des couleurs et de la typographie.</div>\r\n                </li>\r\n            \r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Le Modèle de Boîte (Box Model) <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 1h30</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Comprendre les concepts de margin, border, padding et content pour contrôler l\'espacement des éléments.</div>\r\n                </li>\r\n            \r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Mise en page avec Flexbox <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 2h30</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Maîtriser l\'alignement et la distribution de l\'espace entre les éléments de manière fluide et moderne.</div>\r\n                </li>\r\n            \r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Projet Pratique : Création d\'une Landing Page <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 2h30</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Synthèse des acquis pour réaliser une page web complète, structurée et stylisée de A à Z.</div>\r\n                </li>\r\n            </ul><!-- AI_SYLLABUS_START --><hr style=\"margin: 2rem 0; border: none; border-top: 1px dashed var(--border-color);\"><h4 style=\"color:var(--accent-primary);\">Syllabus Proposé</h4><p style=\"margin-bottom:1rem;\">Découvrez les fondements du Web avec cette formation initiation aux technologies HTML et CSS, conçue pour les débutants. Vous apprendrez à créer des pages web simples, à mettre en forme le contenu et à comprendre les bases de la mise en page web.</p><ul style=\"list-style-type:none; padding:0; margin:0;\">\r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Introduction au CSS <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 1h30</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">Présentation du CSS, syntaxe, sélecteurs, propriétés et valeurs</div>\r\n                </li>\r\n            </ul><!-- AI_SYLLABUS_END --><!-- APTUS_RESOURCES: [{\"id\":\"69e3f6d8c4b31\",\"type\":\"video\",\"titre\":\"chapitre 1\",\"url\":\"https:\\/\\/youtu.be\\/fuWq4RZnc6U?si=n4k8uYZt_MVbCI-Y\",\"date\":\"2026-04-18 23:25:44\"}] -->', 'web ', 'Débutant', '2026-04-17 00:00:00', 'data:image/jpg;base64,', '', 1, 0, '', 'active', NULL, NULL);
INSERT INTO `formation` (`id_formation`, `titre`, `description`, `domaine`, `niveau`, `date_formation`, `image_base64`, `duree`, `id_tuteur`, `is_online`, `lien_api_room`, `statut`, `prerequis_id`, `date_fin`) VALUES
(26, 'Programmation Interactive (JavaScript)', '<p><strong>Apprenez à rendre vos pages dynamiques avec JavaScript.</strong></p><!-- AI_SYLLABUS_START --><hr style=\"margin: 2rem 0; border: none; border-top: 1px dashed var(--border-color);\"><h4 style=\"color:var(--accent-primary);\">Syllabus Proposé</h4><p style=\"margin-bottom:1rem;\">Découvrez le monde de la programmation interactive avec JavaScript. Cette formation vous guidera à travers les bases et les concepts avancés pour créer des expériences web interactives et dynamiques.</p><ul style=\"list-style-type:none; padding:0; margin:0;\">\r\n                <li style=\"margin-bottom: 1rem; background: var(--bg-card); padding: 1rem; border-radius: 8px; border-left: 4px solid var(--accent-primary);\">\r\n                    <div style=\"font-weight: 600; font-size: 1.1rem; margin-bottom: 0.25rem;\">Structures de Contrôle <span style=\"font-size: 0.8rem; font-weight: normal; color: var(--text-secondary); float: right;\">⏳ 2h30</span></div>\r\n                    <div style=\"font-size: 0.95rem; color: var(--text-secondary);\">If/Else, Switch, Boucles For, While, Do-While</div>\r\n                </li>\r\n            </ul><!-- AI_SYLLABUS_END --><!-- APTUS_RESOURCES: [{\"id\":\"69e68e79d7516\",\"type\":\"video\",\"titre\":\"lien pour chap 1 \",\"url\":\"https:\\/\\/youtu.be\\/6FnbPTaoahM?si=uwu-iBIgums4tVLN\",\"date\":\"2026-04-20 22:37:13\"}] -->', 'web ', 'Intermédiaire', '2026-04-20 00:00:00', 'data:image/jpg;base64,', '', 901, 0, '', 'active', 25, NULL);
INSERT INTO `formation` (`id_formation`, `titre`, `description`, `domaine`, `niveau`, `date_formation`, `image_base64`, `duree`, `id_tuteur`, `is_online`, `lien_api_room`, `statut`, `prerequis_id`, `date_fin`) VALUES
