CREATE TABLE `inscription` (
  `id_inscri` int(11) NOT NULL,
  `id_user` int(11) DEFAULT NULL,
  `id_formation` int(11) DEFAULT NULL,
  `date_inscription` datetime DEFAULT current_timestamp(),
